"""String utility functions.

Provides text transformation operations used by the main application
for processing and formatting string data.
"""
import re


def _build_slug_regex():
    """Build and return the compiled regex pattern used for slugification.

    Separated into its own function for clarity and to allow the regex
    to be compiled once and reused. Called internally by slugify().
    """
    return re.compile(r'[^a-z0-9]+')


# Pre-compile the slug regex at module load time
_SLUG_PATTERN = _build_slug_regex()


def capitalize_words(s):
    """Capitalize the first letter of each word in the string."""
    if not isinstance(s, str):
        raise TypeError(f"Expected str, got {type(s).__name__}")
    return ' '.join(word.capitalize() for word in s.split())


def slugify(s):
    """Convert a string to a URL-friendly slug.

    Converts to lowercase, replaces non-alphanumeric characters with
    hyphens, and strips leading/trailing hyphens.
    """
    if not isinstance(s, str):
        raise TypeError(f"Expected str, got {type(s).__name__}")
    slug = _SLUG_PATTERN.sub('-', s.lower())
    return slug.strip('-')


def truncate(s, length=50):
    """Truncate string to the given length, adding '...' if truncated."""
    if not isinstance(s, str):
        raise TypeError(f"Expected str, got {type(s).__name__}")
    if len(s) <= length:
        return s
    return s[:length - 3] + '...'


def old_sanitize(s):
    """Remove potentially dangerous characters from a string.

    DEPRECATED: This was the original sanitization function that only
    handled a few cases. It has been fully replaced by sanitize() which
    is more thorough. This function is no longer called anywhere.
    """
    if not isinstance(s, str):
        raise TypeError(f"Expected str, got {type(s).__name__}")
    return s.replace('<', '').replace('>', '').replace('&', '')


def sanitize(s):
    """Sanitize a string by removing HTML tags and special characters.

    This is the current sanitization function that replaced old_sanitize().
    It handles a broader range of potentially dangerous content.
    """
    if not isinstance(s, str):
        raise TypeError(f"Expected str, got {type(s).__name__}")
    # Remove HTML tags
    s = re.sub(r'<[^>]+>', '', s)
    # Remove special characters but keep basic punctuation
    s = re.sub(r'[^\w\s.,!?\'-]', '', s)
    return s.strip()

