"""Main application module.

Demonstrates usage of the utility functions for processing data.
"""
from utils.math_ops import add, subtract, divide, compute_factorial
from utils.string_ops import capitalize_words, slugify, truncate, sanitize


def process_numbers(data):
    """Process a list of number pairs with various operations."""
    results = []
    for pair in data:
        a, b = pair
        results.append({
            'sum': add(a, b),
            'difference': subtract(a, b),
            'quotient': divide(a, b) if b != 0 else None,
        })
    return results


def process_strings(texts):
    """Process a list of strings through various transformations."""
    processed = []
    for text in texts:
        processed.append({
            'title': capitalize_words(text),
            'slug': slugify(text),
            'preview': truncate(text, 30),
            'clean': sanitize(text),
        })
    return processed


def generate_report(number_data, text_data):
    """Generate a combined report from number and text data."""
    num_results = process_numbers(number_data)
    str_results = process_strings(text_data)
    return {
        'number_results': num_results,
        'string_results': str_results,
        'summary': {
            'pairs_processed': len(num_results),
            'texts_processed': len(str_results),
        }
    }


if __name__ == '__main__':
    numbers = [(10, 3), (7, 2), (15, 5)]
    texts = ["hello world", "Python is <b>great</b>", "A very long string that should be truncated"]
    report = generate_report(numbers, texts)
    print(f"Processed {report['summary']['pairs_processed']} number pairs")
    print(f"Processed {report['summary']['texts_processed']} text items")
